#nullable enable // autogenerated

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Models;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Models;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Models;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.Buffs.Entities
{

    [AutoBuffDefinition(VanillaBuffNames.Entity.burning)]
    public class BurningBuff : BuffDefinition
    {
        public BurningBuff(string nsp, string name) : base(nsp, name)
        {
            AddModelInsertion(LogicModelHelper.ANCHOR_CENTER, VanillaModelKeys.burning, VanillaModelID.burning);
        }
        public override void OnCreate(Buff buff)
        {
            base.OnCreate(buff);
            SetTimer(buff, TimerHelper.NewSecondTimer(SECONDS));
            SetIntervalTimer(buff, TimerHelper.NewSecondTimer(DAMAGE_INTERVAL_SECONDS));
        }
        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff);
            var entity = buff.GetEntity();
            if (entity != null)
            {
                var intervalTimer = GetIntervalTimer(buff);
                if (intervalTimer.RunToExpiredAndNotNull())
                {
                    var damageEffects = new DamageEffectList(VanillaDamageEffects.FIRE, VanillaDamageEffects.IGNORE_ARMOR);
                    entity.TakeDamage(GetFireDamage(buff), damageEffects, entity);
                    entity.Spawn(VanillaEffectID.fireburn, entity.GetCenter());
                    intervalTimer.Reset();
                }

                if (entity.IsInWater())
                {
                    entity.PlaySound(VanillaSoundID.fizz);
                    buff.Remove();
                }
            }
            var timer = GetTimer(buff);
            if (timer.RunToExpiredOrNull())
            {
                buff.Remove();
            }
        }
        public static void MaxTime(Buff buff, int frames)
        {
            var timer = GetTimer(buff);
            if (timer == null || timer.Frame >= frames)
                return;
            timer.ResetTime(frames);
        }
        public static void MaxDamage(Buff buff, float value)
        {
            var damage = GetFireDamage(buff);
            if (damage >= value)
                return;
            SetFireDamage(buff, value);
        }
        public static float GetFireDamage(Buff buff) => buff.GetProperty<float>(PROP_FIRE_DAMAGE);
        public static void SetFireDamage(Buff buff, float value) => buff.SetProperty(PROP_FIRE_DAMAGE, value);
        public static FrameTimer? GetIntervalTimer(Buff buff) => buff.GetProperty<FrameTimer>(PROP_INTERVAL_TIMER);
        public static void SetIntervalTimer(Buff buff, FrameTimer? value) => buff.SetProperty(PROP_INTERVAL_TIMER, value);
        public static FrameTimer? GetTimer(Buff buff) => buff.GetProperty<FrameTimer>(PROP_TIMER);
        public static void SetTimer(Buff buff, FrameTimer? value) => buff.SetProperty(PROP_TIMER, value);
        public const float DAMAGE_INTERVAL_SECONDS = 1f;
        public const float SECONDS = 0f;
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_INTERVAL_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("interval_timer");
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("timer");
        public static readonly VanillaBuffPropertyMeta<float> PROP_FIRE_DAMAGE = new VanillaBuffPropertyMeta<float>("fire_damage", 20f);
    }
}
